const llmOutput = $input.first().json.output || $input.first().json.text || $input.first().json.content;

if (!llmOutput) {
  throw new Error('Kein LLM Output erhalten. Verfugbare Felder: ' + Object.keys($input.first().json).join(', '));
}

const cleaned = llmOutput
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (error) {
  console.error('JSON Parse Error:', error.message);
  console.error('Raw LLM output:', llmOutput.substring(0, 500));
  throw new Error('Invalid JSON from LLM: ' + error.message);
}

if (!parsed.offer_terms || !Array.isArray(parsed.offer_terms)) {
  throw new Error('LLM output missing offer_terms array');
}

const applicant = $('aggregate_applicant_data').first().json;

const today = new Date();
const offerDate = today.getFullYear() + '-' + String(today.getMonth() + 1).padStart(2, '0') + '-' + String(today.getDate()).padStart(2, '0');

const offerTerms = parsed.offer_terms.map(function(term, i) {
  return {
    offer_term: term.offer_term,
    value: String(term.value || '').trim()
  };
});

const jobOffer = {
  doctype: 'Job Offer',
  job_applicant: applicant.applicant_id,
  applicant_name: applicant.applicant_name || applicant.applicant_last_name,
  applicant_email: applicant.applicant_email,
  status: 'Awaiting Response',
  offer_date: offerDate,
  designation: applicant.designation,
  company: 'Universität Duisburg-Essen Consulting',
  job_offer_term_template: 'Standard',
  select_terms: 'ihk-standard',
  offer_terms: offerTerms
};

return {
  json: jobOffer
};

const httpResponse = $input.first().json;
const applicant = httpResponse.data || httpResponse;

const firstName = applicant.custom_vorname || '';
const lastName = applicant.applicant_name || '';
const fullName = (firstName + ' ' + lastName).trim();

const interviewSummary = applicant.custom_interview_summary || '';
const technicalSummary = applicant.custom_summary_technical || '';
const cvSummary = applicant.custom_zusammenfassung_cv || '';

const combinedInterviewNotes = [
  '=== SCREENING-FEEDBACK ===',
  interviewSummary,
  '',
  '=== FACHLICHES-FEEDBACK ===',
  technicalSummary
].join('\n');

const careerEntries = (applicant.custom_beruflicher_werdegang || []).map(function(e, i) {
  return '- ' + (e.custom_cvunternehmen || '') + ' | ' + (e.custom_cvjobtitel__position || '') + ' | ' + (e.custom_cvzeitraum || '');
}).join('\n');

return {
  json: {
    applicant_id: applicant.name,
    applicant_name: fullName,
    applicant_email: applicant.email_id,
    designation: applicant.designation || '',
    job_title: applicant.job_title || '',
    applicant_first_name: applicant.custom_vorname || '',
    applicant_last_name: applicant.applicant_name || '',
    applicant_street: applicant.custom_straße || '',
    applicant_city: applicant.custom_stadt || '',
    applicant_plz: applicant.custom_postleitzahl || '',
    applicant_country: applicant.country || '',
    applicant_nationality: applicant.custom_staatsangehörigkeit || '',
    applicant_phone: applicant.phone_number || '',
    applicant_dob: applicant.custom_geburtsdatum || '',
    applicant_education: applicant.custom_höchster_bildungsabschluss || '',
    applicant_experience_years: applicant.custom_gesamtberufsjahre || 0,
    salary_lower: applicant.lower_range || 0,
    salary_upper: applicant.upper_range || 0,
    currency: applicant.currency || 'EUR',
    interview_summaries: combinedInterviewNotes,
    cv_summary: cvSummary,
    career_history: careerEntries
  }
};

const payload = $json.body || $json;

const applicantId = payload.email_id;

if (!applicantId) {
  throw new Error('Keine job_applicant oder job_applicant_id im Webhook-Payload gefunden. Keys: ' + Object.keys(payload).join(', '));
}

return {
  json: { applicant_id: applicantId }
};
